import { SignIn } from "./pages/SignIn/SignIn";
import { SignUp } from "./pages/SignUp/SignUp";
import './pages/styles/MainStyles.css'

function App() {
  let component
  switch(window.location.pathname){
    case "/":
      component = <SignIn/>
      break
    case "/registr":
      component = <SignUp/>
      break
  }
  return (
    <>
    <header>
        <div class="container">
            <div class="logo">
                <img src="../materials/logo.png" alt="Paw Pals Logo"/>
                <span>PawPals</span>
            </div>
            <nav>
                <a href="#" class="active">Главная</a>
                <a href="About.html">Найти питомца</a>
                <a href="instructors.html">Ваши питомцы</a>
                <a href="contact.html">Контакты</a>
                <a href="RegForm.html" class="no-underline"> <button> Войти</button></a>
            </nav>
        </div>
    </header>
    {component}
    </>
  );
}

export default App;
